from flask import Flask, session, redirect, url_join, request
from flask_oauthlib.client import OAuth2Client
import re

app = Flask(__name__)

# Client configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_BASE_URL = 'https://accounts.google.com/o/oauth2/v2/auth'
TOKEN_BASE_URL = 'https://oauth2.googleapis.com/token'
REDIRECT_URI = request.args.get('redirect_uri')
ALLOWED_DOMAINS = ['yourdomain.com', 'sub.yourdomain.com']

# OAuth 2.0 client
google = OAuth2Client(client_id=CLIENT_ID, client_secret=CLIENT_SECRET, access_token_method='post')

def is_valid_domain(redirect_uri):
    for domain in ALLOWED_DOMAINS:
        if re.match(r'^https?://(www\.)?' + domain + r'(?:\.[^./]+)*(/.*|$)', redirect_uri):
            return True
    return False

def authorize():
    if is_valid_domain(REDIRECT_URI):
        authorization_url, state = google.authorization_flow('oauth2') \
            .authorization_url(redirect_uri=REDIRECT_URI)
        session['oauth2_state'] = state
        return redirect(authorization_url)
    else:
        return "Invalid domain in provided redirect_uri."

def callback():
    if 'oauth2_state' not in session or request.args.get('state') != session['oauth2_state']:
        return "State does not match.", 403

    token = google.authorization_flow('oauth2').redirect_url(request.url, _request=request)
    session['token'] = token['access_token']

    return redirect('/your_application_page')

app.route('/login')(authorize)
app.route('/callback', methods=['GET'])(callback)